1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // ===== Edge cases / simplest =====
6	  it("empty item list yields premium of 5 G (only processing fee)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // ===== Base premiums for main items (newcomer, first contract) =====
15	  it.todo("quote for plain sword (newcomer) — premium 115 G (100 base + 10 first insurance + 5 fee)");
16	  it.todo("quote for plain amulet (newcomer) — premium 71 G (60 base + 6 first insurance + 5 fee)");
17	  it.todo("quote for plain staff (newcomer) — premium 93 G (80 base + 8 first insurance + 5 fee)");
18	  it.todo("quote for plain potion (newcomer) — premium 49 G (40 base + 4 first insurance + 5 fee)");
19	
20	  // ===== Components and building blocks =====
21	  it.todo("2 runes yield 50 G base premium (no block)");
22	  it.todo("3 runes yield 60 G base premium (block of 3 alike applies)");
23	  it.todo("4 runes yield 100 G base premium (no block — block requires exactly 3)");
24	  it.todo("7 runes yield 175 G base premium (no block formation)");
25	  it.todo("2 runes + 1 moonstone yield 75 G base premium (no block: different types)");
26	  it.todo("3 runes + 3 moonstones yield 120 G base premium (two separate blocks)");
27	
28	  // ===== Premium modifiers — thresholds and isolation =====
29	  it.todo("cursed sword adds 50% surcharge on the sword's base premium");
30	  it.todo("sword with exactly enchantment 5 triggers high-enchantment surcharge");
31	  it.todo("sword with enchantment 4 does not trigger high-enchantment surcharge");
32	  it.todo("cursed sword with exactly enchantment 5 triggers both surcharges");
33	  it.todo("customer with exactly 2 years receives 20% loyalty discount");
34	  it.todo("each item in a quote is treated as first insurance (10% surcharge applies even on follow-up contracts)");
35	
36	  // ===== Modifier scope on multi-item policies =====
37	  it.todo("cursed sword + plain amulet — base 160 G + 50 G curse = 210 G before policy modifiers and fee");
38	
39	  // ===== Rounding (MHPCO's favor) =====
40	  it.todo("premium calculation yielding 197.5 G rounds up to 198 G");
41	  it.todo("payout calculation yielding 350.5 G rounds down to 350 G");
42	
43	  // ===== Integration: newcomer with cursed sword =====
44	  it.todo("newcomer (0 years), cursed sword (steel, ench 3) — premium 165 G");
45	
46	  // ===== Integration: long-standing customer's second contract =====
47	  it.todo("3-year customer's 2nd quote, cursed sword (steel, ench 7) — premium 160 G");
48	
49	  // ===== Claim processing: standard reimbursement =====
50	  it.todo("regular sword (steel, ench 3), damage 500 G — payout 400 G (full minus deductible)");
51	  it.todo("rune damage 200 G — payout 100 G (full minus deductible, no special clause)");
52	
53	  // ===== Claim processing: special clauses =====
54	  it.todo("dragon-material sword, ench 5, damage 800 G — payout 700 G (dragon full, then deductible)");
55	  it.todo("steel sword, ench 9, damage 1000 G — payout 400 G (50% then deductible)");
56	  it.todo("dragon-material sword, ench 9, damage 1000 G — payout 400 G (50% wins, then deductible)");
57	  it.todo("dragon-material sword, exact ench 8, damage 1000 G — payout 400 G (50% applies, then deductible)");
58	
59	  // ===== Deductible per damage event =====
60	  it.todo("dragon attack damages sword (500 G) and amulet (300 G) — payout 600 G (deductible per item)");
61	
62	  // ===== Multiple items of same type =====
63	  it.todo("policy covers 2 swords — insurance sum 2000 G, cap 4000 G");
64	  it.todo("dragon attack damages both swords (two sword damages) — each with own deductible");
65	  it.todo("claim with more damage entries of a type than insured — CLI exits non-zero");
66	
67	  // ===== Cap exhaustion =====
68	  it.todo("policy with sword + amulet — insurance sum 1600 G, cap 3200 G");
69	  it.todo("cursed sword — cap stays at 2000 G (based on unmodified insurance value)");
70	  it.todo("policy with sword + 3 runes (block) — insurance sum 1750 G (block discount affects premium only)");
71	  it.todo("sword cap 2000 G, two successive 1500 G claims — payouts 1400 G then 600 G; remainingCap 600 then 0");
72	
73	  // ===== Error cases =====
74	  it.todo("quote with unknown item type — CLI exits non-zero, stderr error, no results");
75	  it.todo("claim references damage for item not in policy — CLI exits non-zero with stderr");
76	  it.todo("claim damage with negative amount — CLI exits non-zero with stderr");
77	
78	  // ===== Multi-step scenario =====
79	  it.todo("scenario: quote then claim referencing it by step index — returns both results in order");
80	});
